<?php
 namespace WPAICG\Core\Stream\Contexts\Chat\Process; use WPAICG\Core\AIPKit_Content_Moderator; use WPAICG\Chat\Storage\LogStorage; use WPAICG\Lib\Chat\Triggers\AIPKit_Trigger_Storage; use WPAICG\Lib\Chat\Triggers\AIPKit_Trigger_Manager; use WP_Error; if (!defined('ABSPATH')) { exit; } function run_content_moderation_logic( string $user_message_text, ?string $client_ip, array $bot_settings, ?LogStorage $log_storage, int $bot_id, ?int $user_id, ?string $session_id ): bool|WP_Error { if (empty($user_message_text)) { return true; } if (!class_exists(AIPKit_Content_Moderator::class)) { return true; } $moderation_context = [ 'client_ip' => $client_ip, 'bot_settings' => $bot_settings, 'module' => 'chat', ]; $moderation_check = AIPKit_Content_Moderator::check_content($user_message_text, $moderation_context); if (is_wp_error($moderation_check)) { $trigger_storage_class = '\WPAICG\Lib\Chat\Triggers\AIPKit_Trigger_Storage'; $trigger_manager_class = '\WPAICG\Lib\Chat\Triggers\AIPKit_Trigger_Manager'; $triggers_enabled = false; if (class_exists('\WPAICG\aipkit_dashboard')) { $triggers_enabled = \WPAICG\aipkit_dashboard::is_pro_plan(); } if ($triggers_enabled && class_exists($trigger_manager_class) && class_exists($trigger_storage_class)) { if ($log_storage) { $error_data = $moderation_check->get_error_data() ?: []; $error_event_context = [ 'error_code' => $moderation_check->get_error_code(), 'error_message' => $moderation_check->get_error_message(), 'bot_id' => $bot_id, 'user_id' => $user_id ?: null, 'session_id' => $session_id, 'module' => 'chat_content_moderation', 'operation' => 'check_user_message', 'status_code' => is_array($error_data) && isset($error_data['status']) ? (int)$error_data['status'] : 400, ]; try { $trigger_storage = new $trigger_storage_class(); $trigger_manager = new $trigger_manager_class($trigger_storage, $log_storage); $trigger_manager->process_event($bot_id, 'system_error_occurred', $error_event_context); } catch (\Exception $e) { } } } $status_code_from_error = is_array($moderation_check->get_error_data()) && isset($moderation_check->get_error_data()['status']) ? (int)$moderation_check->get_error_data()['status'] : 400; return new WP_Error($moderation_check->get_error_code(), $moderation_check->get_error_message(), ['status' => $status_code_from_error]); } return true; } 